insert into medical_knowledge_chunks
(slug, title, topic, locale, text, source, keywords, is_active)
values
  ('dka-1-dka-playbook-emergency-recognition', 'DKA Playbook – Emergency Recognition', 'dka', 'en', 'DKA (Diabetic Ketoacidosis) is a life-threatening emergency. Seek emergency care immediately if you have: fruity-smelling breath, rapid deep breathing (Kussmaul breathing), severe abdominal pain with nausea/vomiting, confusion or decreased alertness, extreme weakness, or loss of consciousness. DKA can develop within 24 hours.', 'DKA Playbook – Emergency Recognition', ARRAY['dka', 'ketoacidosis', 'diabetic ketoacidosis', 'fruity breath', 'kussmaul', 'ketone', 'ketones']::text[], true),
  ('dka-2-dka-playbook-early-recognition', 'DKA Playbook – Early Recognition', 'dka', 'en', 'Early DKA signs: high blood sugar (>250 mg/dL or >14 mmol/L), ketones in urine or blood, dehydration (dry mouth, headache, flushed skin), extreme thirst, frequent urination. If you have diabetes and these symptoms, check ketones and contact your care team or seek care.', 'DKA Playbook – Early Recognition', ARRAY['dka', 'ketone', 'high blood sugar', 'diabetes', 'dehydration', 'thirst']::text[], true),
  ('ketones-3-beyond-the-strip-ketone-monitoring', 'Beyond the Strip – Ketone Monitoring', 'ketones', 'en', 'Ketone monitoring: Check blood ketones (beta-hydroxybutyrate) or urine ketones when blood sugar is high, you are ill, or you have nausea/vomiting. Moderate or large ketones with high blood sugar require urgent action. Small ketones may be managed at home with fluids and insulin per your sick-day plan.', 'Beyond the Strip – Ketone Monitoring', ARRAY['ketone', 'ketones', 'blood ketone', 'urine ketone', 'beta-hydroxybutyrate', 'strip']::text[], true),
  ('dka-4-dka-pathways-to-prevention', 'DKA Pathways to Prevention', 'dka', 'en', 'DKA prevention: Take insulin as prescribed. Have a sick-day plan: check blood sugar and ketones more often when ill. Stay hydrated. Know when to call your provider or go to emergency. Common triggers: missed insulin, infection, illness, certain medications (e.g. SGLT-2 inhibitors, steroids).', 'DKA Pathways to Prevention', ARRAY['dka', 'prevention', 'sick day', 'insulin', 'ketone', 'diabetes']::text[], true),
  ('ketones-5-ketone-conversation-patient-education', 'Ketone Conversation – Patient Education', 'ketones', 'en', 'Ketone conversation with patients: Explain what ketones are (byproducts when the body breaks down fat for energy when insulin is low). Teach when and how to check ketones. Emphasize that moderate/large ketones with high blood sugar mean seek care. Provide a clear action plan.', 'Ketone Conversation – Patient Education', ARRAY['ketone', 'ketones', 'conversation', 'patient', 'education', 'action plan']::text[], true),
  ('dka-6-dka-playbook', 'DKA Playbook', 'dka', 'en', 'People with type 1 or type 2 diabetes can develop DKA. Type 1 is more common, but type 2 can occur especially during illness or with certain medications. Always check ketones when blood sugar is persistently high or you feel unwell.', 'DKA Playbook', ARRAY['type 1', 'type 2', 'diabetes', 'dka', 'ketone']::text[], true);
insert into herbal_remedies
(slug, name, scientific_name, local_names, locale, condition, text, source, evidence_level, contraindications, drug_interactions, blocked_populations, keywords, is_active)
values
  ('nausea-ginger', 'Ginger', 'Zingiber officinale', ARRAY[]::text[], 'en', 'nausea', '**Ginger** (Zingiber officinale): May help with nausea and vomiting. Preparation: Slice 2–3 cm fresh ginger root, steep in hot water for 5–10 minutes as tea. Drink up to 3 cups/day. Generally safe; avoid in large amounts if on blood thinners. Not a substitute for medical care if vomiting is severe.', 'Herbal/Natural – Nausea', 'moderate', ARRAY['gallstones', 'bleeding disorders']::text[], ARRAY['warfarin', 'aspirin', 'anticoagulants', 'antiplatelets']::text[], ARRAY['children_under_2']::text[], ARRAY['nausea', 'vomit', 'ginger', 'sick', 'stomach', 'morning sickness']::text[], true),
  ('malaria-bitter-leaf', 'Bitter leaf', 'Vernonia amygdalina', ARRAY[]::text[], 'en', 'malaria', '**Bitter leaf** (Vernonia amygdalina): Traditionally used for malaria prophylaxis and digestive support in West Africa. Preparation: Wash leaves, squeeze out juice, drink 1–2 tablespoons diluted in water, 1–2 times daily. Evidence is limited; do not replace antimalarial medication. Consult a provider for malaria prevention and treatment.', 'Herbal/Natural – Malaria', 'limited', ARRAY['pregnancy', 'breastfeeding']::text[], ARRAY['diabetes_medications', 'antihypertensives']::text[], ARRAY['pregnant', 'children_under_5']::text[], ARRAY['malaria', 'bitter leaf', 'fever', 'prophylaxis', 'traditional', 'ewuro', 'onugbu']::text[], true),
  ('cough-honey', 'Honey', null, ARRAY[]::text[], 'en', 'cough', '**Honey** (with warm water or lemon): May soothe cough and sore throat in adults and children over 1 year. Preparation: Mix 1–2 teaspoons honey in warm water or herbal tea. Can add lemon juice. Use up to 3 times daily. Do NOT give honey to infants under 1 year (botulism risk).', 'Herbal/Natural – Cough', 'strong', ARRAY['infants_under_1_year', 'diabetes (use sparingly)']::text[], ARRAY[]::text[], ARRAY['children_under_1']::text[], ARRAY['cough', 'honey', 'throat', 'sore throat']::text[], true),
  ('headache-peppermint', 'Peppermint', 'Mentha piperita', ARRAY[]::text[], 'en', 'headache', '**Peppermint** (Mentha piperita): Peppermint tea may help with mild headache and digestive discomfort. Preparation: Steep 1–2 teaspoons dried leaves (or 5–6 fresh leaves) in hot water for 5–7 minutes. Drink up to 3 cups/day. Avoid if you have GERD or gallstones.', 'Herbal/Natural – Headache/Digestive', 'moderate', ARRAY['GERD', 'gallstones', 'hiatal hernia']::text[], ARRAY['cyclosporine', 'antacids']::text[], ARRAY['children_under_2']::text[], ARRAY['headache', 'peppermint', 'mint', 'pain', 'indigestion', 'bloating', 'stomach']::text[], true),
  ('diarrhea-oral-rehydration-solution-ors', 'Oral rehydration solution (ORS)', null, ARRAY[]::text[], 'en', 'diarrhea', '**Oral rehydration solution (ORS)** with zinc: Evidence-based for diarrhea management. Preparation: In 1 litre of clean water, dissolve 6 level teaspoons sugar and ½ level teaspoon salt. Add zinc supplements (20 mg/day for children over 6 months; 10 mg for infants). Continue for 10–14 days. Seek care if diarrhea is severe, bloody, or lasts >3 days.', 'Herbal/Natural – Diarrhea', 'strong', ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['diarrhea', 'diarrhoea', 'loose stool', 'ors', 'rehydration', 'zinc', 'dehydration']::text[], true),
  ('fever-fever-management', 'Fever management', null, ARRAY[]::text[], 'en', 'fever', '**Fever management**: Rest, fluids, and paracetamol are first-line. Some use ginger tea or neem leaf infusion traditionally; evidence is limited. Tepid sponging can help reduce temperature. Seek care if fever is high (>39°C/102°F), lasts >3 days, or occurs with neck stiffness, rash, or confusion.', 'Herbal/Natural – Fever', 'limited', ARRAY['pregnancy (neem)', 'liver disease (neem)']::text[], ARRAY['diabetes_medications (neem)', 'immunosuppressants (neem)']::text[], ARRAY[]::text[], ARRAY['fever', 'temperature', 'neem', 'ginger', 'hot', 'chills']::text[], true),
  ('pain-turmeric', 'Turmeric', 'Curcuma longa', ARRAY[]::text[], 'en', 'pain', '**Turmeric** (Curcuma longa): Anti-inflammatory; may help with mild joint pain and arthritis symptoms. Preparation: Add ½–1 teaspoon turmeric powder to warm milk or food. Adding a pinch of black pepper improves absorption. High-dose supplements can interact with medications. Consult provider if on blood thinners or diabetes medication.', 'Herbal/Natural – Pain/Inflammation', 'moderate', ARRAY['gallstones', 'bile duct obstruction', 'bleeding disorders']::text[], ARRAY['warfarin', 'anticoagulants', 'antiplatelets', 'diabetes_medications']::text[], ARRAY['pregnant']::text[], ARRAY['pain', 'joint', 'arthritis', 'turmeric', 'inflammation', 'swelling', 'ata ile pupa']::text[], true),
  ('fatigue-moringa', 'Moringa', 'Moringa oleifera', ARRAY[]::text[], 'en', 'fatigue', '**Moringa** (Moringa oleifera): Nutrient-rich leaves used for fatigue, malnutrition, and micronutrient supplementation. Preparation: Add 1–2 teaspoons dried moringa leaf powder to food, smoothies, or porridge. Can also cook fresh leaves as vegetable. Generally safe as food. Check with provider if pregnant or on medications.', 'Herbal/Natural – Fatigue/Nutrition', 'moderate', ARRAY['pregnancy (root/bark)', 'thyroid disorders']::text[], ARRAY['thyroid_medications', 'diabetes_medications', 'antihypertensives']::text[], ARRAY[]::text[], ARRAY['tired', 'fatigue', 'weak', 'moringa', 'malnutrition', 'nutrition', 'zogale', 'ewe ile']::text[], true),
  ('skin-infection-neem', 'Neem', 'Azadirachta indica', ARRAY['Dogonyaro']::text[], 'en', 'skin infection', '**Neem** (Azadirachta indica) – Dogonyaro (Hausa): Traditionally used for malaria, skin infections, and oral hygiene across West Africa. Preparation: Boil a small handful of fresh leaves in water for 10–15 minutes; drink ½ cup up to twice daily. For skin: apply cooled leaf wash externally. Neem chewing sticks for oral hygiene. ⚠ Avoid during pregnancy (may cause contractions). Can lower blood sugar—monitor if on diabetes medication.', 'Herbal/Natural – Malaria/Skin/Oral', 'moderate', ARRAY['pregnancy', 'breastfeeding', 'autoimmune disease', 'liver disease', 'trying to conceive']::text[], ARRAY['diabetes_medications', 'immunosuppressants', 'lithium']::text[], ARRAY['pregnant', 'children_under_5']::text[], ARRAY['neem', 'dogonyaro', 'malaria', 'skin', 'infection', 'rash', 'oral', 'mouth', 'teeth', 'boil', 'acne', 'eczema']::text[], true),
  ('hypertension-garlic', 'Garlic', 'Allium sativum', ARRAY[]::text[], 'en', 'hypertension', '**Garlic** (Allium sativum): May support cardiovascular health by helping lower blood pressure and cholesterol. Mild antimicrobial properties. Preparation: Crush 1–2 fresh cloves and let stand 10 minutes before eating (releases allicin). Can add to food or swallow with water. Use 1–2 cloves daily. ⚠ Avoid large supplemental doses if on blood thinners or within 2 weeks of surgery.', 'Herbal/Natural – Blood Pressure/Heart', 'moderate', ARRAY['bleeding disorders', 'pre-surgery (stop 2 weeks before)']::text[], ARRAY['warfarin', 'anticoagulants', 'antiplatelets', 'antihypertensives', 'HIV_protease_inhibitors', 'saquinavir']::text[], ARRAY[]::text[], ARRAY['garlic', 'blood pressure', 'hypertension', 'cholesterol', 'heart', 'ayo', 'albasa']::text[], true),
  ('hypertension-hibiscus', 'Hibiscus', 'Hibiscus sabdariffa', ARRAY['Zobo']::text[], 'en', 'hypertension', '**Hibiscus** (Hibiscus sabdariffa) – Zobo (Nigeria): Hibiscus tea may help reduce mild-to-moderate blood pressure. Rich in antioxidants and vitamin C. Preparation: Steep 1–2 tablespoons dried hibiscus calyces in hot water for 5–10 minutes. Drink 1–3 cups daily. Can serve chilled as zobo. ⚠ May enhance the effect of blood pressure medications—monitor BP. Avoid during pregnancy in large amounts.', 'Herbal/Natural – Blood Pressure', 'moderate', ARRAY['pregnancy (large amounts)', 'low blood pressure']::text[], ARRAY['antihypertensives', 'hydrochlorothiazide', 'chloroquine', 'diabetes_medications']::text[], ARRAY[]::text[], ARRAY['hibiscus', 'zobo', 'blood pressure', 'hypertension', 'bp', 'heart', 'high blood pressure']::text[], true),
  ('diarrhea-guava-leaf', 'Guava leaf', 'Psidium guajava', ARRAY[]::text[], 'en', 'diarrhea', '**Guava leaf** (Psidium guajava): Used traditionally across Nigeria for diarrhea, menstrual cramps, and blood sugar management. Preparation: Boil 4–6 fresh leaves in 1 cup water for 10 minutes. Strain and drink up to twice daily. Some research supports its antidiarrheal and mild blood sugar-lowering effects. ⚠ May interact with diabetes medications—monitor blood sugar.', 'Herbal/Natural – Diarrhea/Blood Sugar', 'moderate', ARRAY['pregnancy (in large amounts)']::text[], ARRAY['diabetes_medications', 'antidiarrheal_drugs']::text[], ARRAY[]::text[], ARRAY['guava', 'guava leaf', 'diarrhea', 'diarrhoea', 'stomach', 'cramps', 'period pain', 'menstrual', 'blood sugar']::text[], true),
  ('stomach-pain-scent-leaf', 'Scent leaf', 'Ocimum gratissimum', ARRAY['Efirin', 'Nchanwu']::text[], 'en', 'stomach pain', '**Scent leaf** (Ocimum gratissimum) – Efirin (Yoruba), Nchanwu (Igbo): Widely used in Nigerian traditional medicine for stomach pain, diarrhea, and upper respiratory infections. Preparation: Squeeze fresh leaves to extract juice; take 1–2 tablespoons. Or boil leaves for tea. Can add to food as seasoning. Has antimicrobial properties supported by in-vitro studies. ⚠ May lower blood sugar—monitor if on diabetes medications.', 'Herbal/Natural – Stomach/Respiratory', 'limited', ARRAY['pregnancy']::text[], ARRAY['diabetes_medications']::text[], ARRAY['pregnant']::text[], ARRAY['scent leaf', 'efirin', 'nchanwu', 'stomach pain', 'stomach ache', 'diarrhea', 'cold', 'catarrh', 'respiratory']::text[], true),
  ('dengue-support-pawpaw-papaya-leaf', 'Pawpaw / Papaya leaf', 'Carica papaya', ARRAY[]::text[], 'en', 'dengue support', '**Pawpaw / Papaya leaf** (Carica papaya): Papaya leaf extract is traditionally used to support platelet recovery during dengue fever and as a digestive aid. Preparation: Crush 2–3 fresh mature leaves, squeeze through cloth to extract juice. Take 1–2 tablespoons twice daily for up to 5 days. Tastes very bitter—can mix with honey. ⚠ Do NOT use during pregnancy (papain may cause uterine contractions). Do not substitute for medical care in dengue/malaria.', 'Herbal/Natural – Dengue/Digestion', 'moderate', ARRAY['pregnancy', 'breastfeeding', 'latex allergy', 'blood thinners']::text[], ARRAY['warfarin', 'anticoagulants', 'amiodarone']::text[], ARRAY['pregnant']::text[], ARRAY['pawpaw', 'papaya', 'dengue', 'platelet', 'digestion', 'stomach', 'ibepe', 'gwanda']::text[], true),
  ('toothache-clove', 'Clove', 'Syzygium aromaticum', ARRAY['Kanafuru']::text[], 'en', 'toothache', '**Clove** (Syzygium aromaticum) – Kanafuru (Yoruba): Contains eugenol, a natural analgesic. Effective for toothache and oral pain relief. Preparation: Place a whole clove against the sore tooth and bite gently, or apply a drop of clove oil on cotton wool to the affected area. For sore throat: steep 3–4 cloves in hot water as tea. ⚠ Do not swallow clove oil undiluted. Avoid large amounts if on blood thinners.', 'Herbal/Natural – Dental/Oral Pain', 'moderate', ARRAY['bleeding disorders', 'liver disease']::text[], ARRAY['warfarin', 'anticoagulants', 'antiplatelets']::text[], ARRAY['children_under_2']::text[], ARRAY['clove', 'kanafuru', 'toothache', 'tooth pain', 'dental', 'oral pain', 'mouth sore', 'gum']::text[], true),
  ('burns-aloe-vera', 'Aloe vera', 'Aloe barbadensis', ARRAY[]::text[], 'en', 'burns', '**Aloe vera** (Aloe barbadensis): Gel from the inner leaf soothes minor burns, sunburn, and skin irritation. Preparation: Cut a fresh leaf, scoop out the clear gel, and apply directly to affected skin. Reapply 2–3 times daily. For constipation: some use a small amount of inner-leaf juice orally, but this can cause cramping—use cautiously. ⚠ Do not apply gel to deep wounds. Oral use may lower blood sugar.', 'Herbal/Natural – Burns/Skin', 'strong', ARRAY['deep wounds', 'pregnancy (oral)', 'kidney disease (oral)']::text[], ARRAY['diabetes_medications', 'digoxin', 'diuretics', 'laxatives']::text[], ARRAY[]::text[], ARRAY['aloe', 'aloe vera', 'burn', 'sunburn', 'skin', 'wound', 'rash', 'constipation']::text[], true),
  ('cold-lemongrass', 'Lemongrass', 'Cymbopogon citratus', ARRAY[]::text[], 'en', 'cold', '**Lemongrass** (Cymbopogon citratus): Used traditionally across Nigeria for fever, colds, and body aches. Has mild antimicrobial and anti-inflammatory properties. Preparation: Bruise 2–3 stalks (or use dried leaves), boil in water for 10–15 minutes. Strain and drink warm, up to 3 cups/day. ⚠ May lower blood pressure. Avoid large amounts during pregnancy.', 'Herbal/Natural – Cold/Body Aches', 'limited', ARRAY['pregnancy (large amounts)', 'low blood pressure']::text[], ARRAY['antihypertensives', 'sedatives']::text[], ARRAY[]::text[], ARRAY['lemongrass', 'cold', 'body ache', 'body pain', 'flu', 'catarrh', 'kooko oba', 'fever']::text[], true),
  ('dry-skin-shea-butter', 'Shea butter', 'Vitellaria paradoxa', ARRAY['Ori', 'Man shanu']::text[], 'en', 'dry skin', '**Shea butter** (Vitellaria paradoxa) – Ori (Yoruba), Man shanu (Hausa): Traditional skin emollient widely used in West Africa for dry skin, eczema, minor cuts, and joint/muscle pain (topical). Preparation: Warm a small amount between palms and massage into affected skin. For nasal congestion (traditional): rub under nostrils. Rich in vitamins A, E, and fatty acids. ⚠ For external use only. Test on small area first if you have latex or nut allergies.', 'Herbal/Natural – Skin/Joint (Topical)', 'traditional', ARRAY['latex allergy', 'nut allergy (test first)']::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['shea butter', 'ori', 'dry skin', 'eczema', 'skin', 'moisturizer', 'joint pain', 'muscle pain', 'rash']::text[], true),
  ('congestion-eucalyptus', 'Eucalyptus', 'Eucalyptus globulus', ARRAY[]::text[], 'en', 'congestion', '**Eucalyptus** (Eucalyptus globulus): Steam inhalation with eucalyptus leaves may relieve nasal congestion and respiratory symptoms. Preparation: Add a small handful of crushed eucalyptus leaves (or 2–3 drops eucalyptus oil) to a bowl of hot water. Cover head with towel and inhale steam for 5–10 minutes. Repeat 2–3 times daily. ⚠ Do NOT ingest eucalyptus oil—it is toxic if swallowed. Keep oil away from children''s faces. Do not use near eyes.', 'Herbal/Natural – Respiratory/Congestion', 'moderate', ARRAY['asthma (may worsen)', 'epilepsy']::text[], ARRAY['diabetes_medications', 'liver-metabolized drugs (CYP)']::text[], ARRAY['children_under_2']::text[], ARRAY['eucalyptus', 'congestion', 'blocked nose', 'cold', 'catarrh', 'sinusitis', 'respiratory', 'inhaler', 'steam']::text[], true),
  ('skin-fungal-coconut-oil', 'Coconut oil', 'Cocos nucifera', ARRAY[]::text[], 'en', 'skin fungal', '**Coconut oil** (Cocos nucifera): Used topically for skin moisturising, mild fungal infections (antifungal properties of lauric acid), and oil pulling for oral health. Preparation: For skin, apply virgin coconut oil directly. For oil pulling: swish 1 tablespoon in mouth for 10–15 minutes, then spit out—do not swallow. ⚠ High in saturated fat if consumed in large dietary quantities.', 'Herbal/Natural – Skin/Oral Health', 'moderate', ARRAY['coconut allergy']::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['coconut', 'coconut oil', 'skin', 'fungal', 'ringworm', 'dry skin', 'oil pulling', 'oral', 'adi agbon']::text[], true),
  ('blood-sugar-support-utazi-leaf', 'Utazi leaf', 'Gongronema latifolium', ARRAY[]::text[], 'en', 'blood sugar support', '**Utazi leaf** (Gongronema latifolium): Used in southeastern Nigeria for blood sugar management and digestive support. Preparation: Chew 2–3 fresh leaves before meals, or boil leaves to make tea—drink ½ cup up to twice daily. Also used in soups. Some Nigerian studies suggest mild hypoglycemic effects. ⚠ May cause excessive blood sugar lowering if combined with diabetes medications—monitor blood sugar closely.', 'Herbal/Natural – Blood Sugar/Digestive', 'limited', ARRAY['pregnancy', 'hypoglycemia']::text[], ARRAY['diabetes_medications', 'insulin', 'metformin', 'glimepiride']::text[], ARRAY['pregnant', 'children_under_5']::text[], ARRAY['utazi', 'blood sugar', 'diabetes', 'sugar', 'digestion', 'appetite', 'gongronema']::text[], true),
  ('hypertension-soursop-leaf', 'Soursop leaf', 'Annona muricata', ARRAY[]::text[], 'en', 'hypertension', '**Soursop leaf** (Annona muricata) – Sawansop: Traditionally used in West Africa for hypertension and as a calming agent. Preparation: Boil 5–6 dried leaves in 2 cups water for 15 minutes. Strain and drink ½ cup up to twice daily. Some preliminary studies suggest blood pressure-lowering and sedative effects. ⚠ Do NOT use long-term or in high doses—annonacin in seeds/bark has been linked to neurotoxicity. Use leaves only, short-term.', 'Herbal/Natural – Blood Pressure/Calm', 'limited', ARRAY['pregnancy', 'Parkinson''s disease', 'liver disease', 'kidney disease']::text[], ARRAY['antihypertensives', 'sedatives', 'antidepressants', 'diabetes_medications']::text[], ARRAY['pregnant']::text[], ARRAY['soursop', 'sawansop', 'graviola', 'blood pressure', 'hypertension', 'sleep', 'calm', 'anxiety', 'abo']::text[], true);
insert into herbal_drug_interaction_rules
(herb_keywords, drug_keywords, severity, message_template, source, locale, is_active)
values
  (ARRAY['ginger', 'turmeric', 'garlic', 'clove', 'pawpaw', 'papaya']::text[], ARRAY['warfarin', 'heparin', 'enoxaparin', 'rivaroxaban', 'apixaban']::text[], 'critical', 'Serious bleeding risk. {herb} can increase anticoagulant effects of {drug}. Do NOT combine without direct supervision from your prescribing doctor.', 'interaction-table', 'en', true),
  (ARRAY['bitter leaf', 'moringa', 'neem', 'utazi', 'guava leaf', 'scent leaf', 'aloe vera', 'soursop', 'hibiscus']::text[], ARRAY['metformin', 'glimepiride', 'glibenclamide', 'insulin', 'gliclazide']::text[], 'major', 'Risk of dangerously low blood sugar (hypoglycemia). {herb} may enhance the blood-sugar-lowering effect of {drug}. Monitor blood sugar closely and consult your provider before combining.', 'interaction-table', 'en', true),
  (ARRAY['garlic', 'hibiscus', 'soursop', 'lemongrass', 'moringa']::text[], ARRAY['amlodipine', 'lisinopril', 'enalapril', 'losartan', 'nifedipine', 'atenolol', 'hydrochlorothiazide']::text[], 'major', 'Risk of excessively low blood pressure. {herb} may enhance the effect of {drug}. Monitor BP regularly and tell your doctor you are using this remedy.', 'interaction-table', 'en', true),
  (ARRAY['neem']::text[], ARRAY['cyclosporine', 'tacrolimus', 'azathioprine', 'mycophenolate']::text[], 'major', 'Neem may stimulate the immune system and counteract immunosuppressant medications. Do NOT combine.', 'interaction-table', 'en', true),
  (ARRAY['pawpaw', 'papaya']::text[], ARRAY['amiodarone']::text[], 'major', 'Papaya leaf may increase amiodarone levels. Avoid combining.', 'interaction-table', 'en', true),
  (ARRAY['turmeric', 'ginger']::text[], ARRAY['aspirin', 'ibuprofen', 'diclofenac', 'naproxen']::text[], 'moderate', 'May increase bleeding risk when combined with anti-inflammatory drugs. Use food-level amounts only; avoid high-dose supplements.', 'interaction-table', 'en', true),
  (ARRAY['aloe vera']::text[], ARRAY['digoxin']::text[], 'moderate', 'Aloe vera (oral) may lower potassium, increasing digoxin toxicity risk. Monitor potassium levels.', 'interaction-table', 'en', true),
  (ARRAY['aloe vera', 'neem']::text[], ARRAY['diuretics', 'furosemide', 'hydrochlorothiazide']::text[], 'moderate', 'May increase risk of electrolyte imbalance (low potassium). Stay hydrated and monitor if combining.', 'interaction-table', 'en', true),
  (ARRAY['soursop', 'lemongrass']::text[], ARRAY['diazepam', 'lorazepam', 'alprazolam', 'zolpidem']::text[], 'moderate', 'May enhance sedative effects. Avoid driving or operating machinery if combining.', 'interaction-table', 'en', true),
  (ARRAY['hibiscus']::text[], ARRAY['chloroquine']::text[], 'moderate', 'Hibiscus may reduce chloroquine absorption. Separate intake by at least 2 hours if using both.', 'interaction-table', 'en', true),
  (ARRAY['eucalyptus']::text[], ARRAY['diabetes_medications', 'metformin']::text[], 'moderate', 'Eucalyptus may lower blood sugar. Monitor if on diabetes medication.', 'interaction-table', 'en', true),
  (ARRAY['peppermint']::text[], ARRAY['antacids', 'omeprazole', 'pantoprazole']::text[], 'minor', 'Peppermint may affect absorption of antacid medications. Separate intake by 30 minutes.', 'interaction-table', 'en', true),
  (ARRAY['turmeric']::text[], ARRAY['paracetamol', 'acetaminophen']::text[], 'minor', 'High-dose turmeric supplements alongside frequent paracetamol may increase liver workload. Food-level turmeric is fine.', 'interaction-table', 'en', true);
